verify-retry-behavior.script:
test -f reports/retry-on-script-failure.attempts.log || {
  echo '[ERROR] missing retry-on-script-failure attempts log'
  exit 1
}
test -f reports/retry-on-any-failure.attempts.log || {
  echo '[ERROR] missing retry-on-any-failure attempts log'
  exit 1
}
test -f reports/retry-on-timeout.attempts.log || {
  echo '[ERROR] missing retry-on-timeout attempts log'
  exit 1
}
grep -F 'attempt=0' reports/retry-on-script-failure.attempts.log || {
  echo '[ERROR] retry-on-script-failure never started'
  exit 1
}
grep -F 'attempt=2' reports/retry-on-script-failure.attempts.log || {
  echo '[ERROR] retry-on-script-failure did not reach success attempt'
  exit 1
}
grep -F 'success_at=2' reports/retry-on-script-failure.status || {
  echo '[ERROR] retry-on-script-failure success marker mismatch'
  exit 1
}
grep -F 'attempt=1' reports/retry-on-any-failure.attempts.log || {
  echo '[ERROR] retry-on-any-failure did not retry as expected'
  exit 1
}
grep -F 'success_at=1' reports/retry-on-any-failure.status || {
  echo '[ERROR] retry-on-any-failure success marker mismatch'
  exit 1
}
grep -F 'attempt=2' reports/retry-on-timeout.attempts.log || {
  echo '[ERROR] retry-on-timeout did not exhaust retry attempts'
  exit 1
}
grep -F 'timeout_expected=true' reports/retry-on-timeout.status || {
  echo '[ERROR] retry-on-timeout marker mismatch'
  exit 1
}
